// frontend/src/components/RoleManager.js
import { useEffect, useState } from "react";
import { roles as RoleApi } from "../services/api";

export default function RoleManager({ onChanged }) {
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [newRole, setNewRole] = useState("");

    const refresh = async () => {
        setLoading(true);
        try {
            const rows = await RoleApi.list(); // [{id,name,systemRole,description,count}]
            setItems(Array.isArray(rows) ? rows : []);
            onChanged?.();
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        refresh();
    }, []);

    const add = async () => {
        const name = newRole.trim();
        if (!name) return;
        try {
            await RoleApi.create(name);
            setNewRole("");
            await refresh();
        } catch (e) {
            alert(e?.response?.data?.message || e.message);
        }
    };

    const remove = async (r) => {
        if (r.systemRole) return alert("Không thể xóa vai trò hệ thống");
        if (r.count > 0)
            return alert(
                `Vai trò đang được ${r.count} người dùng. Hãy chuyển role cho họ trước khi xóa.`
            );
        if (!confirm(`Xóa vai trò '${r.name}'?`)) return;
        try {
            await RoleApi.remove(r.id);
            await refresh();
        } catch (e) {
            alert(e?.response?.data?.message || e.message);
        }
    };

    return (
        <div className="border rounded-2xl p-4 bg-slate-50">
            <div className="flex items-center justify-between mb-2">
                <div className="font-semibold">Quản lý vai trò</div>
                <button
                    onClick={refresh}
                    className="text-sm px-2 py-1 rounded-lg border hover:bg-white"
                >
                    Tải lại
                </button>
            </div>

            <div className="text-sm text-slate-500 mb-2">Vai trò hiện có:</div>
            <div className="space-y-2 max-h-44 overflow-auto pr-1">
                {loading ? (
                    <div className="text-sm text-slate-500">Đang tải…</div>
                ) : items.length === 0 ? (
                    <div className="text-sm text-slate-500">Chưa có vai trò nào</div>
                ) : (
                    items.map((r) => (
                        <div
                            key={r.id}
                            className="flex items-center justify-between bg-white rounded-xl px-3 py-2 shadow-sm"
                        >
                            <div className="flex items-center gap-2">
                                <span className="text-sm">{r.name}</span>
                                {r.systemRole && (
                                    <span className="text-xs px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700">
                    mặc định
                  </span>
                                )}
                                <span className="text-xs text-slate-500">({r.count})</span>
                            </div>
                            <div className="flex items-center gap-3">
                                <button
                                    className={`text-sm ${
                                        r.systemRole
                                            ? "opacity-40 cursor-not-allowed"
                                            : "text-rose-600 hover:underline"
                                    }`}
                                    onClick={() => remove(r)}
                                    disabled={r.systemRole}
                                >
                                    Xóa
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="mt-3">
                <div className="text-sm text-slate-500 mb-1">Thêm vai trò mới:</div>
                <div className="flex gap-2">
                    <input
                        value={newRole}
                        onChange={(e) => setNewRole(e.target.value)}
                        placeholder="Tên vai trò (ví dụ: Kế toán trưởng)"
                        className="flex-1 border rounded-xl px-3 py-2 outline-none focus:ring-2 ring-indigo-200"
                    />
                    <button
                        onClick={add}
                        className="px-4 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700"
                    >
                        Thêm
                    </button>
                </div>
                <div className="text-xs text-slate-500 mt-1">
                    Tên sẽ tự động chuyển thành CHU_CÁI_IN_HOA_KHÔNG_DẤU ở backend.
                </div>
            </div>
        </div>
    );
}
